(function () {
  'use strict';

  const Overlay = () => {
    document.querySelector("#settings").addEventListener("click", ($event) => {
      document.querySelector("#overlay").removeAttribute("hidden");
    });

    document.querySelector("#close").addEventListener("click", ($event) => {
      document.querySelector("#overlay").setAttribute("hidden", true);
    });
  };

  class Todo {
    constructor(name, tag, todoItem) {
      this.id = Math.floor(Math.random() * (12345 + 1) + 1);
      this.name = name;
      this.tag = tag;
      this.todoItem = todoItem;
      // console.log({ name: this.name, tag: this.tag, todo: this.todoItem });
    }
  }

  const { ipcRenderer } = require("electron");

  Overlay();
  let todo = [];
  todo.push(
    new Todo("First Todo", "Test", {
      name: "Gotta crate object",
      status: "incomplete",
      tag: "Test",
      dateCreated: new Date(),
    })
  );
  todo.push(
    new Todo("Second Todo", "Test 2", {
      name: "Gotta fix object",
      status: "incomplete",
      tag: "Test",
      dateCreated: new Date(),
    })
  );
  // console.log(todo);

  document.querySelector(".lists-container").innerHTML = `<ul class="lists"></ul>`;

  todo.forEach((todo) => {
    console.log(todo);
    document.querySelector(".lists").innerHTML += `<li onclick="getTodoInfo(todo.name)">${todo.name}</li>`;
  });
  // ipcRenderer.sendSync("synchronous-message", {
  //   settings: { notifications: true },
  // });

  // In renderer process (web page).

  ipcRenderer.on("asynchronous-reply", (event, arg) => {
    console.log(arg); // prints "pong"
  });

}());
